import{_ as t,o as i,c as r,a0 as a}from"./chunks/framework.BWpMpcZ2.js";const m=JSON.parse('{"title":"margin","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),n={name:"index.md"};function o(s,e,l,g,c,d){return i(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="margin" tabindex="-1">margin <a class="header-anchor" href="#margin" aria-label="Permalink to &quot;margin&quot;">​</a></h1><p>Margin is an open-source, local-first AI writing studio for Markdown users.</p><p>Think of it as SillyTavern for story writing: a customizable environment where writers can collaborate with context-aware AI agents, swap models, manage prompts, and build their own creative workflows -- all while keeping their work on their own machine.</p><p>Instead of treating AI as a chat window, Margin integrates it directly into the writing process. Draft scenes, brainstorm plots, maintain world lore, rewrite passages, and iterate on ideas inside a distraction-free editor designed for long-form writing.</p><h3 id="why-margin" tabindex="-1">Why margin? <a class="header-anchor" href="#why-margin" aria-label="Permalink to &quot;Why margin?&quot;">​</a></h3><ul><li><strong>Markdown-Native Writing Environment</strong> -- A distraction-free editor designed for long-form writing projects and documentation.</li><li><strong>Runs Locally</strong> -- Your manuscripts, notes, and context stay on your machine. No required cloud services or telemetry.</li><li><strong>Optimized for Local Models</strong> -- Works well with lightweight language models and supports Ollama, LM Studio, and OpenAI-compatible providers.</li><li><strong>Automatic Context Management</strong> -- Organize characters, lore, outlines, and style guides into folders. Margin automatically includes the relevant context for each task.</li><li><strong>Customizable AI Workflows</strong> -- Configure prompts, agents, and writing pipelines to match your process instead of adapting to rigid presets.</li><li><strong>Interactive Diff Review</strong> -- Review AI-generated edits with clear inline diffs before accepting or rejecting changes.</li></ul><h3 id="sections" tabindex="-1">Sections <a class="header-anchor" href="#sections" aria-label="Permalink to &quot;Sections&quot;">​</a></h3><ul><li><a href="./getting-started.html">Getting Started</a> -- System requirements, installation, and first launch.</li><li><a href="./configuration/general.html">Configuration</a> -- All settings explained: workspace, appearance, context, endpoints.</li><li><a href="./writing-guide.html">Writing Guide</a> -- How AI assist works, character profiles, style guides, manifests, and custom prompts.</li></ul><h3 id="quick-links" tabindex="-1">Quick Links <a class="header-anchor" href="#quick-links" aria-label="Permalink to &quot;Quick Links&quot;">​</a></h3><ul><li><strong>GitHub</strong>: <a href="https://github.com/prxshetty/margin" target="_blank" rel="noreferrer">github.com/prxshetty/margin</a></li><li><strong>Report an Issue</strong>: <a href="https://github.com/prxshetty/margin/issues" target="_blank" rel="noreferrer">github.com/prxshetty/margin/issues</a></li></ul>',10)])])}const u=t(n,[["render",o]]);export{m as __pageData,u as default};
